code = """import json
import re

# Load quote line items
quote_lines = locals().get('var_functions.query_db:6')
if isinstance(quote_lines, str):
    with open(quote_lines, 'r') as f:
        quote_lines = json.load(f)

# Load volume discount policy
volume_discount_article = locals().get('var_functions.query_db:26')
if isinstance(volume_discount_article, str):
    with open(volume_discount_article, 'r') as f:
        volume_discount_article = json.load(f)

# Find the Volume-Based Discounts article
discount_article = None
for article in volume_discount_article:
    if 'volume-based discounts' in article.get('title', '').lower():
        discount_article = article
        break

# Extract discount rules from the article content
content = discount_article.get('faq_answer__c', '').lower()

# Find all discount rules - look for patterns like "X% discount for purchases over $Y"
discount_rules = []
pattern = r'(\d+)%\s*discount[^$]*\$([\d,]+)'
matches = re.findall(pattern, content, re.IGNORECASE)

for match in matches:
    discount_percent = int(match[0])
    threshold = int(match[1].replace(',', ''))
    discount_rules.append({'discount': discount_percent, 'threshold': threshold})

# Sort by threshold
discount_rules.sort(key=lambda x: x['threshold'])

# Load installation policy if needed for setup compliance
installation_article = None
for article in volume_discount_article:
    if 'installation timeline' in article.get('title', '').lower():
        installation_article = article
        break

print("__RESULT__:")
print(json.dumps({
    'discount_rules': discount_rules,
    'volume_discount_article_id': discount_article.get('id') if discount_article else None,
    'installation_article_id': installation_article.get('id') if installation_article else None,
    'quote_total': sum(float(line['TotalPrice']) for line in quote_lines),
    'quote_line_items': len(quote_lines)
}))"""

